SELECT b.*, u.username as author_name, up.avatar as author_avatar FROM blog b LEFT JOIN user u ON b.author_id = u.id LEFT JOIN user_profile up ON u.id = up.user_id WHERE b.deleted_at IS NULL AND b.status = 1
AND (b.title LIKE CONCAT('%', #{keyword}, '%') OR b.tags LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY b.created_at DESC LIMIT #{offset}, #{size}

SELECT b.*, u.username as author_name, up.avatar as author_avatar FROM blog b LEFT JOIN user u ON b.author_id = u.id LEFT JOIN user_profile up ON u.id = up.user_id WHERE b.author_id = #{authorId} AND b.deleted_at IS NULL
AND b.status = #{status}
ORDER BY b.created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM blog b
WHERE b.author_id = #{authorId} AND b.deleted_at IS NULL

    AND b.status = #{status}

